refsection.programlisting:
image = imread(fullpath(getIPCVpath() + "/images/opencv_smarties.png"));
image = imresize(rgb2gray(image), [120 160]);
mask = imthreshold(image, 120) > 0;
[labels,count] = imconnectedcomponents(mask, 8);
props = imregionprops(labels);
disp(props(1).Area);
subplot(1, 2, 1);
imshow(image);
subplot(1, 2, 2);
imshow(imlabel2rgb(labels));
